final:
module top_module (
    input e,
    input z,
    input x,
    output reg not_c
);
    always @(*) begin
        case ({e, z, x})
            3'b000: not_c = 1'b1;
            3'b011: not_c = 1'b1;
            3'b101: not_c = 1'b1;
            3'b100: not_c = 1'b1;
            3'b010: not_c = 1'b1;
            3'b001: not_c = 1'b1;
            3'b111: not_c = 1'b1;
            3'b110: not_c = 1'b0;
        endcase
    end
endmodule
